const logoutBtn=document.getElementById("logout");logoutBtn&&logoutBtn.addEventListener("click",async t=>{t.preventDefault();try{const t=await fetch("../back/router.php?action=logout",{method:"POST",credentials:"same-origin"});(await t.json()).success&&(window.location.href="../back/router.php?action=home")}catch(t){console.error(t)}});